mapper.select:
SELECT FROM borrow_record br LEFT JOIN sys_user u ON br.user_id = u.id AND u.deleted = 0 LEFT JOIN book b ON br.book_id = b.id AND b.deleted = 0 WHERE br.deleted = 0
AND br.user_id = #{userId}
AND br.book_id = #{bookId}
AND br.status = #{status}
AND (u.username LIKE CONCAT('%', #{keyword}, '%') OR u.real_name LIKE CONCAT('%', #{keyword}, '%') OR u.reader_no LIKE CONCAT('%', #{keyword}, '%') OR b.title LIKE CONCAT('%', #{keyword}, '%') OR br.record_no LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY br.borrow_date DESC
